#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

class Solution {
public:
    int solve(vector<vector<int>> jobs, vector<int> workers) {
        sort(jobs.begin(), jobs.end(), [](const vector<int>& a, const vector<int>& b) {
            return a[1] < b[1];
        });
        sort(workers.begin(), workers.end());
        int count = 0;
        for (int i = 0; i < jobs.size(); i++) {
            while (workers.size() && workers[0] < jobs[i][0]) {
                workers.erase(workers.begin());
            }
            if (workers.size()) {
                workers[0] -= jobs[i][0];
                count++;
                sort(workers.begin(), workers.end());
            }
        }
        return count;
    }
};

int main() {
    vector<vector<int>> jobs = {{1, 1, 1}, {2, 2, 2}, {3, 3, 3}, {4, 4, 4}, {5, 5, 5}};
    vector<int> workers = {6, 6, 6};
    Solution solution;
    cout << solution.solve(jobs, workers) << endl;
    return 0;
}
